SELECT GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Item No_], GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Location Code], GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Trademark code], GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Season code], "GIAC" AS CAT_1, IIf(IsNull([GiacenzaLiberaVeloce_step1_GiacenzaAssortita.location code])=True,[GiacenzaLiberaVeloce_step0_GiacenzaTotale].[qty],[GiacenzaLiberaVeloce_step0_GiacenzaTotale].[qty]-[GiacenzaLiberaVeloce_step1_GiacenzaAssortita].[qty]) AS qty, "SFUSO" AS CAT_2
FROM GiacenzaLiberaVeloce_step0_GiacenzaTotale LEFT JOIN GiacenzaLiberaVeloce_step1_GiacenzaAssortita ON (GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Location Code] = GiacenzaLiberaVeloce_step1_GiacenzaAssortita.[Location Code]) AND (GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Item No_] = GiacenzaLiberaVeloce_step1_GiacenzaAssortita.[Item No_])
WHERE (((IIf(IsNull([GiacenzaLiberaVeloce_step1_GiacenzaAssortita.location code])=True,[GiacenzaLiberaVeloce_step0_GiacenzaTotale].[qty],[GiacenzaLiberaVeloce_step0_GiacenzaTotale].[qty]-[GiacenzaLiberaVeloce_step1_GiacenzaAssortita].[qty]))>0));

